const input = $json || {};
const args = input.args && typeof input.args === 'object' ? input.args : {};
const commandText = String(input.commandText || '').trim().toLowerCase();
const commandType = String(args.commandType || '').trim().toLowerCase();
const additionalDestinations = Array.isArray(args.additionalDestinations)
  ? args.additionalDestinations
  : [];

function detectCommandType() {
  if (commandType) return commandType;
  if (/release\s+sprint|close\s+sprint|release\s+status/.test(commandText)) return 'release_sprint';
  if (/(^|\b)(approve|ok|dong y|đồng ý|xac nhan|xác nhận)(\b|$)/i.test(commandText)) return 'approve';
  if (/(^|\b)(reject|tu choi|từ chối)(\b|$)/i.test(commandText)) return 'reject';
  if (/(^|\b)(cancel|huy|hủy)(\b|$)/i.test(commandText)) return 'cancel';
  return 'help';
}

const normalizedCommandType = detectCommandType();

const resultByType = {
  release_sprint: 'Release sprint hiện mới là route demo thôi nha. Tạm thời mình giữ focus vào check sprint để flow chính chạy ổn trước đã.',
  approve: 'Lệnh approve hiện mới là khung demo thôi nha, chưa có pending action thật nào được gắn vào flow chính lúc này.',
  reject: 'Lệnh reject hiện mới là khung demo thôi nha, nên thread này chưa có action thật để từ chối đâu.',
  cancel: 'Lệnh cancel hiện mới là khung demo thôi nha, nên thread này chưa có action thật để huỷ đâu.',
};

function normalizeDestinations(rawDestinations) {
  if (!Array.isArray(rawDestinations)) return [];

  const normalized = [];
  const seen = new Set();
  for (const rawDestination of rawDestinations) {
    const type = typeof rawDestination === 'string'
      ? rawDestination.trim()
      : String(rawDestination?.type || '').trim();

    if (!type || seen.has(type)) continue;
    seen.add(type);
    normalized.push({ type });
  }

  return normalized;
}

const resultText = normalizedCommandType === 'help'
  ? 'Hiện mình hỗ trợ ổn nhất các lệnh: check sprint, status sprint. Các nhánh demo đang dựng khung để ráp sau: release sprint, approve, reject, cancel.'
  : resultByType[normalizedCommandType];

const destinations = normalizeDestinations([
  { type: 'reply' },
  ...additionalDestinations,
]);
const destinationTypes = destinations.map((destination) => destination.type);

return {
  toolName: 'assistantDemoCommand',
  resultText,
  deliveryPlan: {
    thread: {
      threadKey: `assistant-demo-${normalizedCommandType}`,
    },
    destinations,
    messages: [
      {
        messageKey: 'reply',
        type: 'text',
        destinations: destinationTypes,
        payload: {
          text: resultText,
        },
      },
    ],
  },
};
